url_options.body_graphql_query:
{
  WorkshopDevice(name__value: "$device") {
    edges {
      node {
        id
        name { value }
        asn { value }
        site_name { value }
        role { value }
        maintenance { value }
      }
    }
  }
}

{
  WorkshopInterface(role__values: ["peer", "mgmt"], device__name__value: "$device") {
    edges {
      node {
        name { value }
        role { value }
        ip_address { value }
        expected_state { value }
      }
    }
  }
}
